<?php
$pageTitle='Digital License Control';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('digital_license_control');
$pdo=getDB();$products=$pdo->query('SELECT id,sku,name FROM '.table('products').' WHERE downloadable=1 OR active=1 ORDER BY name LIMIT 500')->fetchAll();$customers=$pdo->query('SELECT id,customer_code,contact_name,email,company_name FROM '.table('customers').' ORDER BY created_at DESC LIMIT 500')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){try{$action=(string)($_POST['action']??'pool');if($action==='assign'){ecom33AssignDigitalLicense($pdo,(int)$_POST['digital_license_pool_id'],(int)($_POST['order_id']??0)?:null,(int)($_POST['customer_id']??0)?:null,trim((string)$_POST['customer_email']),trim((string)$_POST['assigned_to_name']));flash('success','Digital license assigned.');}else{ecom33AddDigitalLicense($pdo,(int)($_POST['product_id']??0)?:null,trim((string)$_POST['pool_name']),trim((string)$_POST['license_code']),trim((string)$_POST['serial_number']),trim((string)$_POST['activation_link']));flash('success','Digital license added.');}}catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'digital-license-control']);flash('error',$e->getMessage());}redirect(ADMIN_URL.'/erp/digital-license-control.php');}
$pools=$pdo->query('SELECT lp.*,p.name product_name,p.sku FROM '.table('digital_license_pools').' lp LEFT JOIN '.table('products').' p ON p.id=lp.product_id ORDER BY FIELD(lp.status,"available","assigned"),lp.created_at DESC LIMIT 300')->fetchAll();
$assignments=$pdo->query('SELECT a.*,lp.pool_number,lp.pool_name FROM '.table('digital_license_assignments').' a LEFT JOIN '.table('digital_license_pools').' lp ON lp.id=a.digital_license_pool_id ORDER BY a.created_at DESC LIMIT 200')->fetchAll();
$deliveries=$pdo->query('SELECT d.*,a.assignment_number FROM '.table('digital_license_deliveries').' d LEFT JOIN '.table('digital_license_assignments').' a ON a.id=d.digital_license_assignment_id ORDER BY d.created_at DESC LIMIT 200')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Digital Delivery</div><h2 class="h4 mb-1">Digital License Control</h2><p class="text-secondary mb-0">Manage software license keys, activation links, serials, customer assignments and delivery queue.</p></div></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><h2 class="h5 mb-3">Add License</h2><select class="form-select mb-2" name="product_id"><option value="">No product</option><?php foreach($products as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['sku'].' · '.$p['name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="pool_name" placeholder="License pool name"><textarea class="form-control mb-2" name="license_code" rows="3" placeholder="License key/code"></textarea><input class="form-control mb-2" name="serial_number" placeholder="Serial number"><input class="form-control mb-3" name="activation_link" placeholder="Activation link"><button class="btn btn-brand w-100">Add License</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="assign"><h2 class="h5 mb-3">Assign License</h2><select class="form-select mb-2" name="digital_license_pool_id"><?php foreach($pools as $p): if($p['status']!=='available')continue; ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['pool_number'].' · '.$p['pool_name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" type="number" name="order_id" placeholder="Order ID optional"><select class="form-select mb-2" name="customer_id"><option value="">No customer</option><?php foreach($customers as $c): ?><option value="<?php echo (int)$c['id']; ?>"><?php echo esc($c['customer_code'].' · '.($c['company_name']?:$c['contact_name'])); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="customer_email" placeholder="Customer email"><input class="form-control mb-3" name="assigned_to_name" placeholder="Assigned to name"><button class="btn btn-outline-primary w-100">Assign</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">License Pool</h2><table class="table"><thead><tr><th>License</th><th>Product</th><th>Status</th></tr></thead><tbody><?php foreach($pools as $p): ?><tr><td><strong><?php echo esc($p['pool_number']); ?></strong><div class="small text-secondary"><?php echo esc($p['pool_name'].' · '.$p['serial_number']); ?></div></td><td><?php echo esc($p['sku'].' · '.$p['product_name']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($p['status'])); ?>"><?php echo esc($p['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Assignments</h2><table class="table"><thead><tr><th>Assignment</th><th>License</th><th>Customer</th><th>Delivery</th></tr></thead><tbody><?php foreach($assignments as $a): ?><tr><td><strong><?php echo esc($a['assignment_number']); ?></strong><div class="small text-secondary"><?php echo esc($a['assigned_at']); ?></div></td><td><?php echo esc($a['pool_number'].' · '.$a['pool_name']); ?></td><td><?php echo esc($a['customer_email']); ?></td><td><?php echo esc($a['delivery_status']); ?></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Delivery Queue</h2><table class="table"><tbody><?php foreach($deliveries as $d): ?><tr><td><strong><?php echo esc($d['assignment_number']); ?></strong><div class="small text-secondary"><?php echo esc($d['recipient_email'].' · '.$d['delivery_subject']); ?></div></td><td><span class="badge bg-<?php echo esc(statusTone($d['status'])); ?>"><?php echo esc($d['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>